class Solution:
    def maximumPossibleSize(self, nums):
        n = len(nums)
        memo = {}
        import sys
        sys.setrecursionlimit(10000)
        def dp(i):
            # returns dict count -> minimal first-group value for suffix nums[i:]
            if i == n:
                return {0: -1}
            if i in memo:
                return memo[i]
            best = {}
            M = -1
            for j in range(i, n):
                if nums[j] > M:
                    M = nums[j]
                if j + 1 == n:
                    cands = [(0, float('inf'))]
                else:
                    sub = dp(j + 1)
                    cands = [(c, fv) for c, fv in sub.items() if fv >= M]
                for c, fv in cands:
                    nc = c + 1
                    if nc not in best or M < best[nc]:
                        best[nc] = M
            memo[i] = best
            return best
        front = dp(0)
        return max(front.keys())

