var maximumPossibleSize = function(nums) {
    let floor = 0;
    let count = 0;
    let cur = 0;
    let started = false;
    for (const x of nums) {
        cur = started ? Math.max(cur, x) : x;
        started = true;
        if (cur >= floor) {
            count++;
            floor = cur;
            started = false;
            cur = 0;
        }
    }
    return count;
};
